/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels.
 * The notification service checks these preferences before dispatching
 * to channel adapters.
 *
 * DECISION CHANGE (Multi-Channel Notification Support):
 * =====================================================
 * This model was originally designed assuming email-only notifications
 * (Session 3). With the addition of SMS (Session 8) and webhook support,
 * the email-only assumption is no longer valid.
 *
 * Changes made:
 * 1. Introduced a generic `ChannelPreferences` interface shared by all
 *    channels (email, SMS, webhook) to avoid duplicating structure.
 * 2. `UserNotificationPreferences` now has `email`, `sms`, and `webhook` fields.
 * 3. Added `UpdateChannelPreferencesInput` as a generic update input type.
 * 4. `getDefaultEmailPreferences()` replaced by channel-specific defaults
 *    via `getDefaultChannelPreferences()`.
 * 5. Backward compatibility: `EmailPreferences` and `EmailFrequency` types
 *    are preserved as aliases so existing code continues to compile.
 */

import type { NotificationType } from './notification.js';

/**
 * Delivery frequency for a notification channel.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary (not yet implemented)
 * - 'weekly-digest': batch into a weekly summary (not yet implemented)
 * - 'none': do not send notifications on this channel
 */
export type DeliveryFrequency = 'immediate' | 'daily-digest' | 'weekly-digest' | 'none';

/**
 * Backward-compatible alias — existing code referencing EmailFrequency
 * continues to work without changes.
 */
export type EmailFrequency = DeliveryFrequency;

/**
 * Generic per-channel notification preferences.
 * Every channel (email, SMS, webhook) shares this structure.
 */
export interface ChannelPreferences {
  /** Master toggle for this channel. */
  enabled: boolean;
  /** How often notifications are delivered on this channel. */
  frequency: DeliveryFrequency;
  /** Notification categories the user is subscribed to on this channel. */
  subscribedCategories: NotificationType[];
}

/**
 * Backward-compatible alias — existing code referencing EmailPreferences
 * continues to work.
 */
export type EmailPreferences = ChannelPreferences;

/**
 * All notification categories a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order:confirmation',
  'order:status-update',
  'user:welcome',
  'user:profile-updated',
];

/**
 * The channels that support per-user preferences.
 */
export type PreferenceChannel = 'email' | 'sms' | 'webhook';

/**
 * User notification preferences — persisted per user.
 * Contains per-channel settings for email, SMS, and webhook.
 */
export interface UserNotificationPreferences {
  id: string;
  userId: string;
  email: ChannelPreferences;
  sms: ChannelPreferences;
  webhook: ChannelPreferences;
  updatedAt: Date;
}

/**
 * Generic input for updating any channel's preferences.
 */
export interface UpdateChannelPreferencesInput {
  enabled?: boolean;
  frequency?: DeliveryFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Backward-compatible alias for email-specific update input.
 */
export type UpdateEmailPreferencesInput = UpdateChannelPreferencesInput;

/**
 * Returns default preferences for a channel.
 *
 * - email: enabled, immediate delivery, all categories
 * - sms: enabled, immediate delivery, all categories
 * - webhook: disabled by default (requires explicit opt-in with a URL)
 */
export function getDefaultChannelPreferences(channel: PreferenceChannel): ChannelPreferences {
  if (channel === 'webhook') {
    return {
      enabled: false,
      frequency: 'none',
      subscribedCategories: [],
    };
  }

  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Backward-compatible helper — returns default email preferences.
 */
export function getDefaultEmailPreferences(): ChannelPreferences {
  return getDefaultChannelPreferences('email');
}

/**
 * Repository for UserNotificationPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Serializes per-channel preferences (email, SMS, webhook) to flat
 * database records and deserializes them back to domain objects.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserNotificationPreferences, ChannelPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { DeliveryFrequency, PreferenceChannel } from '../models/user-preferences.js';
import { getDefaultChannelPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

const CHANNELS: PreferenceChannel[] = ['email', 'sms', 'webhook'];

export class PreferencesRepository extends BaseRepository<UserNotificationPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserNotificationPreferences {
    const prefs: UserNotificationPreferences = {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: this.channelToDomain(record, 'email'),
      sms: this.channelToDomain(record, 'sms'),
      webhook: this.channelToDomain(record, 'webhook'),
      updatedAt: new Date(record['updatedAt'] as string),
    };
    return prefs;
  }

  protected toRecord(entity: UserNotificationPreferences): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      userId: entity.userId,
      updatedAt: entity.updatedAt.toISOString(),
    };

    for (const channel of CHANNELS) {
      const cp = entity[channel];
      record[`${channel}Enabled`] = cp.enabled;
      record[`${channel}Frequency`] = cp.frequency;
      record[`${channel}SubscribedCategories`] = JSON.stringify(cp.subscribedCategories);
    }

    return record;
  }

  /**
   * Deserialize a single channel's preferences from a flat record.
   * Falls back to defaults if the channel fields are missing (backward
   * compatibility for records created before multi-channel support).
   */
  private channelToDomain(record: DatabaseRecord, channel: PreferenceChannel): ChannelPreferences {
    const enabledKey = `${channel}Enabled`;
    const frequencyKey = `${channel}Frequency`;
    const categoriesKey = `${channel}SubscribedCategories`;

    if (record[enabledKey] === undefined) {
      return getDefaultChannelPreferences(channel);
    }

    return {
      enabled: record[enabledKey] as boolean,
      frequency: record[frequencyKey] as DeliveryFrequency,
      subscribedCategories: JSON.parse(record[categoriesKey] as string) as NotificationType[],
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserNotificationPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for per-channel notification preferences and
 * exposes a generic `shouldSend(channel, userId, type)` method for the
 * notification service to check whether a notification should be delivered
 * on a given channel.
 *
 * Depends on:
 * - PreferencesRepository for data access
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserNotificationPreferences,
  UpdateChannelPreferencesInput,
  PreferenceChannel,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { getDefaultChannelPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns defaults if none are persisted.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    return {
      id: '',
      userId,
      email: getDefaultChannelPreferences('email'),
      sms: getDefaultChannelPreferences('sms'),
      webhook: getDefaultChannelPreferences('webhook'),
      updatedAt: new Date(),
    };
  }

  /**
   * Update preferences for a specific channel. Creates the preferences
   * record if it doesn't exist yet.
   */
  updateChannelPreferences(
    userId: string,
    channel: PreferenceChannel,
    input: UpdateChannelPreferencesInput,
  ): UserNotificationPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);

    if (existing) {
      const currentChannel = existing[channel];
      const updated: UserNotificationPreferences = {
        ...existing,
        [channel]: {
          enabled: input.enabled ?? currentChannel.enabled,
          frequency: input.frequency ?? currentChannel.frequency,
          subscribedCategories:
            input.subscribedCategories ?? currentChannel.subscribedCategories,
        },
        updatedAt: new Date(),
      };
      this.preferencesRepository.update(existing.id, updated);
      this.logger.info(`Updated ${channel} preferences for user ${userId}`);
      return updated;
    }

    const prefs: UserNotificationPreferences = {
      id: generatePreferencesId(),
      userId,
      email: getDefaultChannelPreferences('email'),
      sms: getDefaultChannelPreferences('sms'),
      webhook: getDefaultChannelPreferences('webhook'),
      updatedAt: new Date(),
    };

    const defaults = getDefaultChannelPreferences(channel);
    prefs[channel] = {
      enabled: input.enabled ?? defaults.enabled,
      frequency: input.frequency ?? defaults.frequency,
      subscribedCategories:
        input.subscribedCategories ?? defaults.subscribedCategories,
    };

    this.preferencesRepository.save(prefs);
    this.logger.info(`Created preferences for user ${userId} (${channel} update)`);
    return prefs;
  }

  /**
   * Backward-compatible method — updates email preferences.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateChannelPreferencesInput,
  ): UserNotificationPreferences {
    return this.updateChannelPreferences(userId, 'email', input);
  }

  /**
   * Generic preference check — should a notification of the given type
   * be sent to the user on the specified channel?
   *
   * Returns true if:
   * - The user has no persisted preferences (defaults allow email/SMS)
   * - The channel is enabled AND the category is subscribed AND frequency is not 'none'
   */
  shouldSend(channel: PreferenceChannel, userId: string, notificationType: NotificationType): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences stored — use defaults
    if (!prefs) {
      const defaults = getDefaultChannelPreferences(channel);
      if (!defaults.enabled) {
        return false;
      }
      return defaults.subscribedCategories.includes(notificationType);
    }

    const channelPrefs = prefs[channel];

    if (!channelPrefs.enabled) {
      this.logger.info(`${channel} disabled for user ${userId}, skipping ${notificationType}`);
      return false;
    }

    if (channelPrefs.frequency === 'none') {
      this.logger.info(`${channel} frequency is none for user ${userId}, skipping ${notificationType}`);
      return false;
    }

    if (!channelPrefs.subscribedCategories.includes(notificationType)) {
      this.logger.info(
        `User ${userId} not subscribed to ${notificationType} on ${channel}, skipping`,
      );
      return false;
    }

    return true;
  }

  /**
   * Backward-compatible method — checks email preferences.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSend('email', userId, notificationType);
  }
}

