import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return defaults when no preferences exist', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should return default SMS preferences (enabled, immediate)', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.frequency).toBe('immediate');
      expect(prefs.sms.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should return default webhook preferences (disabled)', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.frequency).toBe('none');
      expect(prefs.webhook.subscribedCategories).toEqual([]);
    });

    it('should return stored preferences when they exist', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily-digest' });
      const prefs = service.getPreferences('user-1');

      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.email.enabled).toBe(true);
    });
  });

  describe('updateEmailPreferences (backward-compatible)', () => {
    it('should create preferences on first update', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        enabled: false,
      });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(false);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should update existing preferences', () => {
      service.updateEmailPreferences('user-1', { enabled: true });
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly-digest',
      });

      expect(updated.email.enabled).toBe(true);
      expect(updated.email.frequency).toBe('weekly-digest');
    });

    it('should update subscribed categories', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order:confirmation'],
      });

      expect(prefs.email.subscribedCategories).toEqual(['order:confirmation']);
    });

    it('should preserve unspecified fields when updating', () => {
      service.updateEmailPreferences('user-1', {
        enabled: true,
        frequency: 'daily-digest',
        subscribedCategories: ['order:confirmation', 'order:status-update'],
      });

      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly-digest',
      });

      expect(updated.email.enabled).toBe(true);
      expect(updated.email.frequency).toBe('weekly-digest');
      expect(updated.email.subscribedCategories).toEqual([
        'order:confirmation',
        'order:status-update',
      ]);
    });

    it('should generate sequential IDs for new preferences', () => {
      const prefs1 = service.updateEmailPreferences('user-1', {});
      const prefs2 = service.updateEmailPreferences('user-2', {});

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('updateChannelPreferences', () => {
    it('should update SMS preferences independently of email', () => {
      service.updateChannelPreferences('user-1', 'email', { frequency: 'daily-digest' });
      const prefs = service.updateChannelPreferences('user-1', 'sms', { enabled: false });

      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.sms.enabled).toBe(false);
    });

    it('should create preferences with SMS update on first call', () => {
      const prefs = service.updateChannelPreferences('user-1', 'sms', {
        subscribedCategories: ['order:confirmation'],
      });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.sms.subscribedCategories).toEqual(['order:confirmation']);
      // Email should still have defaults
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should update webhook preferences', () => {
      const prefs = service.updateChannelPreferences('user-1', 'webhook', {
        enabled: true,
        frequency: 'immediate',
        subscribedCategories: ['order:confirmation', 'order:status-update'],
      });

      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.frequency).toBe('immediate');
      expect(prefs.webhook.subscribedCategories).toEqual([
        'order:confirmation',
        'order:status-update',
      ]);
    });

    it('should preserve other channels when updating one channel', () => {
      service.updateChannelPreferences('user-1', 'email', { frequency: 'daily-digest' });
      service.updateChannelPreferences('user-1', 'sms', { frequency: 'weekly-digest' });
      const prefs = service.updateChannelPreferences('user-1', 'webhook', {
        enabled: true,
        frequency: 'immediate',
        subscribedCategories: ['order:confirmation'],
      });

      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.sms.frequency).toBe('weekly-digest');
      expect(prefs.webhook.enabled).toBe(true);
    });
  });

  describe('shouldSendEmail (backward-compatible)', () => {
    it('should return true when no preferences are stored (defaults)', () => {
      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.updateEmailPreferences('user-1', {
        enabled: true,
        frequency: 'immediate',
        subscribedCategories: ['order:confirmation'],
      });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'order:status-update')).toBe(false);
    });

    it('should return false when frequency is none', () => {
      service.updateEmailPreferences('user-1', { frequency: 'none' });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order:confirmation'],
      });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'order:status-update')).toBe(false);
    });

    it('should return false when subscribed categories is empty', () => {
      service.updateEmailPreferences('user-1', {
        subscribedCategories: [],
      });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
    });

    it('should allow daily-digest frequency', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily-digest' });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
    });

    it('should handle preferences for different users independently', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      service.updateEmailPreferences('user-2', { enabled: true });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-2', 'order:confirmation')).toBe(true);
    });
  });

  describe('shouldSend (generic, multi-channel)', () => {
    it('should return true for SMS with defaults (no stored preferences)', () => {
      expect(service.shouldSend('sms', 'user-1', 'order:confirmation')).toBe(true);
    });

    it('should return false for webhook with defaults (disabled by default)', () => {
      expect(service.shouldSend('webhook', 'user-1', 'order:confirmation')).toBe(false);
    });

    it('should respect SMS-specific preferences', () => {
      service.updateChannelPreferences('user-1', 'sms', { enabled: false });

      expect(service.shouldSend('sms', 'user-1', 'order:confirmation')).toBe(false);
      // Email should still be allowed
      expect(service.shouldSend('email', 'user-1', 'order:confirmation')).toBe(true);
    });

    it('should respect SMS subscribed categories', () => {
      service.updateChannelPreferences('user-1', 'sms', {
        subscribedCategories: ['order:confirmation'],
      });

      expect(service.shouldSend('sms', 'user-1', 'order:confirmation')).toBe(true);
      expect(service.shouldSend('sms', 'user-1', 'order:status-update')).toBe(false);
    });

    it('should allow webhook when explicitly enabled', () => {
      service.updateChannelPreferences('user-1', 'webhook', {
        enabled: true,
        frequency: 'immediate',
        subscribedCategories: ['order:confirmation'],
      });

      expect(service.shouldSend('webhook', 'user-1', 'order:confirmation')).toBe(true);
      expect(service.shouldSend('webhook', 'user-1', 'order:status-update')).toBe(false);
    });

    it('should return false for SMS when frequency is none', () => {
      service.updateChannelPreferences('user-1', 'sms', { frequency: 'none' });

      expect(service.shouldSend('sms', 'user-1', 'order:confirmation')).toBe(false);
    });

    it('should handle per-channel preferences independently per user', () => {
      service.updateChannelPreferences('user-1', 'sms', { enabled: false });
      service.updateChannelPreferences('user-2', 'sms', { enabled: true });

      expect(service.shouldSend('sms', 'user-1', 'order:confirmation')).toBe(false);
      expect(service.shouldSend('sms', 'user-2', 'order:confirmation')).toBe(true);
    });
  });
});

